<!-- wp:heading {"level":3,"className":"pillar-title","style":{"typography":{"fontSize":"var(\u002d\u002dwp\u002d\u002dpreset\u002d\u002dfont-size\u002d\u002d2xl)","fontFamily":"var(\u002d\u002dfont-display)"},"color":{"text":"var(\u002d\u002dwp\u002d\u002dpreset\u002d\u002dcolor\u002d\u002dc-gold)"}}} -->
<h3 class="wp-block-heading pillar-title has-text-color" style="color:var(--wp--preset--color--c-gold);font-family:var(--font-display);font-size:var(--wp--preset--font-size--2xl)">The Shadow Tide</h3>
<!-- /wp:heading -->

<!-- wp:paragraph {"className":"pillar-text","style":{"typography":{"fontSize":"var(\u002d\u002dwp\u002d\u002dpreset\u002d\u002dfont-size\u002d\u002dlg)"},"color":{"text":"var(\u002d\u002dwp\u002d\u002dpreset\u002d\u002dcolor\u002d\u002dc-ash)"}}} -->
<p class="pillar-text has-text-color" style="color:var(--wp--preset--color--c-ash);font-size:var(--wp--preset--font-size--lg)">From beyond the Veil comes the Shadow Tide — a creeping corruption that devours memory, warps flesh, and turns the faithful into hollow vessels. It cannot be fought with steel alone. It requires sacrifice, cunning, and choices no hero wants to make.</p>
<!-- /wp:paragraph --></article>
